    private boolean isValidSession(UserSessionDTO session) {
        return session.getUsername() != null && 
               session.getUsername().matches("^[a-zA-Z0-9_]{3,50}$");
    }

    private String sanitizeOutput(String input) {
        return input.replaceAll("[<>\"'&]", "");
    }
}

// Immutable DTO with explicit fields only
public final class UserSessionDTO {
    private final String username;
    private final long timestamp;

    @JsonCreator
    public UserSessionDTO(
            @JsonProperty("username") String username,
            @JsonProperty("timestamp") long timestamp) {
        this.username = username;
        this.timestamp = timestamp;
    }

    public String getUsername() { return username; }
    public long getTimestamp() { return timestamp; }
}
```

**Key Security Controls**:
- **Never use Java native serialization** for untrusted data - use JSON, Protocol Buffers, or XML with explicit schemas
- **Immutable DTOs with @JsonCreator** - only explicitly defined fields are populated
- **Jackson configured restrictively** - fails on unknown properties, preventing polymorphic injection
- **Input size limits** - prevents resource exhaustion attacks

If you're forced to use Java serialization (which should be temporary while migrating), you need multiple layers of defense. Here's a production-hardened approach:

**PRODUCTION PATTERN**:

```java
import java.io.*;
import java.util.Set;
import java.util.HashSet;
import java.util.logging.Logger;
import javax.servlet.http.*;

public class HardenedDeserializationServlet extends HttpServlet {

    private static final Logger logger = Logger.getLogger(
        HardenedDeserializationServlet.class.getName());

    // Layer 1: Strict allowlist of permitted classes
    private static final Set<String> ALLOWED_CLASSES = Set.of(
        "com.myapp.dto.UserSession",
        "com.myapp.dto.SessionToken",
        "java.lang.String",
        "java.lang.Long",
        "java.util.Date"
    );

    // Layer 2: Known dangerous classes to block (defense in depth)
    private static final Set<String> BLOCKED_PREFIXES = Set.of(
        "org.apache.commons.collections",
        "org.apache.commons.beanutils",
        "org.springframework.beans",
        "com.sun.org.apache.xalan",
        "javax.management",
        "java.rmi",
        "sun.rmi",
        "com.mchange.v2.c3p0",
        "org.codehaus.groovy.runtime"
    );

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response)
            throws IOException {

        // Layer 3: Input size limit
        if (request.getContentLength() > 65536) {
            logSecurityEvent(request, "OVERSIZED_PAYLOAD");
            response.sendError(413, "Payload too large");
            return;
        }

        // Layer 4: Rate limiting check (assume injected limiter)
        if (!rateLimiter.tryAcquire(request.getRemoteAddr())) {
            logSecurityEvent(request, "RATE_LIMIT_EXCEEDED");
            response.sendError(429, "Too many requests");
            return;
        }

        byte[] data = request.getInputStream().readAllBytes();

        try (SafeObjectInputStream sois = new SafeObjectInputStream(
                new ByteArrayInputStream(data), ALLOWED_CLASSES, BLOCKED_PREFIXES)) {

            Object obj = sois.readObject();

            // Layer 5: Post-deserialization validation
            if (obj instanceof UserSession session) {
                if (!validateSession(session)) {
                    logSecurityEvent(request, "INVALID_SESSION_DATA");
                    response.sendError(400, "Invalid session");
                    return;
                }
                processValidSession(session, response);
            } else {
                logSecurityEvent(request, "UNEXPECTED_OBJECT_TYPE");
                response.sendError(400, "Invalid data type");
            }

        } catch (SecurityException e) {
            // Layer 6: Security exceptions are potential attacks
            logSecurityEvent(request, "BLOCKED_DESERIALIZATION: " + e.getMessage());
            alertSecurityTeam(request, e);
            response.sendError(400, "Invalid data");

        } catch (Exception e) {
            logger.warning("Deserialization error: " + e.getMessage());
            response.sendError(400, "Invalid data format");
        }
    }

    private void logSecurityEvent(HttpServletRequest req, String event) {
        logger.severe(String.format(
            "SECURITY_EVENT: %s | IP: %s | UA: %s | Path: %s",
            event, req.getRemoteAddr(), req.getHeader("User-Agent"),
            req.getRequestURI()));
    }

    private void alertSecurityTeam(HttpServletRequest req, Exception e) {
        // Integration with SIEM/alerting system
        securityAlertService.sendAlert(
            AlertLevel.CRITICAL,
            "Deserialization attack detected",
            Map.of("ip", req.getRemoteAddr(), "exception", e.getMessage()));
    }
}

/**
 * Custom ObjectInputStream with allowlist-based class filtering
 */
public class SafeObjectInputStream extends ObjectInputStream {

    private final Set<String> allowedClasses;
    private final Set<String> blockedPrefixes;

    public SafeObjectInputStream(InputStream in, Set<String> allowed, 
            Set<String> blocked) throws IOException {
        super(in);
        this.allowedClasses = allowed;
        this.blockedPrefixes = blocked;
    }

    @Override
    protected Class<?> resolveClass(ObjectStreamClass desc) 
            throws IOException, ClassNotFoundException {

        String className = desc.getName();

        // Check blocklist first (fail fast on known gadgets)
        for (String prefix : blockedPrefixes) {
            if (className.startsWith(prefix)) {
                throw new SecurityException(
                    "Blocked dangerous class: " + className);
            }
        }

        // Then check allowlist
        if (!allowedClasses.contains(className) && 
            !className.startsWith("[")) { // Allow primitive arrays
            throw new SecurityException(
                "Class not in allowlist: " + className);
        }

        return super.resolveClass(desc);
    }
}
