Deserialization vulnerabilities are a critical security concern. In the 2023 GoAnywhere MFT breach (CVE-2023-0669), unsafe deserialization allowed attackers to compromise 130+ organizations. While Go's standard JSON library is safer than many languages, there are still significant risks with certain patterns.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/gob"
	"encoding/json"
	"net/http"
	"os/exec"
	"reflect"
)

// Dangerous: Allows arbitrary type instantiation
var typeRegistry = make(map[string]reflect.Type)

func RegisterType(name string, t reflect.Type) {
	typeRegistry[name] = t
}

type DynamicPayload struct {
	TypeName string          `json:"type"`
	Data     json.RawMessage `json:"data"`
}

type Command struct {
	Name string   `json:"name"`
	Args []string `json:"args"`
}

func (c *Command) Execute() (string, error) {
	// DANGEROUS: Executes system commands from deserialized data
	out, err := exec.Command(c.Name, c.Args...).Output()
	return string(out), err
}

func handleDynamicPayload(w http.ResponseWriter, r *http.Request) {
	var payload DynamicPayload

	// VULNERABLE: Deserializes without validation
	if err := json.NewDecoder(r.Body).Decode(&payload); err != nil {
		http.Error(w, err.Error(), 400)
		return
	}

	// DANGEROUS: Creates arbitrary types based on user input
	if t, ok := typeRegistry[payload.TypeName]; ok {
		instance := reflect.New(t).Interface()
		json.Unmarshal(payload.Data, instance)

		// Execute if it has Execute method
		if executer, ok := instance.(interface{ Execute() (string, error) }); ok {
			result, _ := executer.Execute()
			w.Write([]byte(result))
		}
	}
}

func handleGobDecode(w http.ResponseWriter, r *http.Request) {
	// VULNERABLE: gob can deserialize arbitrary registered types
	dec := gob.NewDecoder(r.Body)
	var cmd Command
	if err := dec.Decode(&cmd); err == nil {
		cmd.Execute() // Remote code execution
	}
}
```

**Attack Payload**:
```json
