**Why This Is Dangerous**:
- Dynamic type instantiation allows attackers to create arbitrary objects
- Deserialized data directly controls system command execution
- No validation of payload structure, types, or values
- gob encoding can instantiate any registered type, enabling gadget chains
- Trusts external data without integrity verification

**SECURE VERSION**:

```go
package main

import (
	"crypto/hmac"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"errors"
	"log"
	"net/http"
	"regexp"
)

// Strict struct with validated fields only
type UserConfig struct {
	UserID    string   `json:"user_id"`
	Theme     string   `json:"theme"`
	Language  string   `json:"language"`
	Features  []string `json:"features"`
}

var (
	allowedThemes    = map[string]bool{"light": true, "dark": true, "system": true}
	allowedLanguages = map[string]bool{"en": true, "es": true, "fr": true, "de": true}
	allowedFeatures  = map[string]bool{"notifications": true, "analytics": true, "beta": true}
	userIDPattern    = regexp.MustCompile(`^[a-zA-Z0-9]{8,32}$`)
	secretKey        = []byte("your-256-bit-secret-from-env") // Load from env
)

func (c *UserConfig) Validate() error {
	if !userIDPattern.MatchString(c.UserID) {
		return errors.New("invalid user_id format")
	}
	if !allowedThemes[c.Theme] {
		return errors.New("invalid theme")
	}
	if !allowedLanguages[c.Language] {
		return errors.New("invalid language")
	}
	for _, f := range c.Features {
		if !allowedFeatures[f] {
			return errors.New("invalid feature: " + f)
		}
	}
	if len(c.Features) > 10 {
		return errors.New("too many features")
	}
	return nil
}

func verifyHMAC(data []byte, signature string) bool {
	mac := hmac.New(sha256.New, secretKey)
	mac.Write(data)
	expected := hex.EncodeToString(mac.Sum(nil))
	return hmac.Equal([]byte(expected), []byte(signature))
}

func handleSecureConfig(w http.ResponseWriter, r *http.Request) {
	// Limit request body size
	r.Body = http.MaxBytesReader(w, r.Body, 4096)

	// Verify HMAC signature from trusted source
	signature := r.Header.Get("X-Signature")
	if signature == "" {
		http.Error(w, "missing signature", http.StatusUnauthorized)
		return
	}

	// Read body for signature verification
	body := make([]byte, 4096)
	n, _ := r.Body.Read(body)
	body = body[:n]

	if !verifyHMAC(body, signature) {
		log.Printf("SECURITY: Invalid signature from %s", r.RemoteAddr)
		http.Error(w, "invalid signature", http.StatusForbidden)
		return
	}

	// Deserialize to strict typed struct only
	var config UserConfig
	if err := json.Unmarshal(body, &config); err != nil {
		log.Printf("Invalid JSON from %s: %v", r.RemoteAddr, err)
		http.Error(w, "invalid json", http.StatusBadRequest)
		return
	}

	// Validate all fields against allowlist
	if err := config.Validate(); err != nil {
		log.Printf("Validation failed from %s: %v", r.RemoteAddr, err)
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	log.Printf("Valid config received for user: %s", config.UserID)
	w.WriteHeader(http.StatusOK)
}
```

**Key Security Controls**:
- **Strict typed structs**: Only deserialize into predefined structures, never dynamic types
- **HMAC signature verification**: Ensures data integrity from trusted sources
- **Comprehensive validation**: Every field validated against strict allowlists
- **Request size limits**: Prevents resource exhaustion attacks
- **Security logging**: Tracks suspicious deserialization attempts

Complex systems with plugins or multiple data sources require a defense-in-depth approach with cryptographic integrity verification, sandboxed execution, and strict schema validation.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/ed25519"
	"crypto/sha256"
	"encoding/base64"
	"encoding/json"
	"errors"
	"fmt"
	"log/slog"
	"os"
	"sync"
	"time"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promauto"
)

// Metrics for monitoring
var (
	deserializationAttempts = promauto.NewCounterVec(
		prometheus.CounterOpts{
			Name: "deserialization_attempts_total",
			Help: "Total deserialization attempts by source and status",
		},
		[]string{"source", "schema", "status"},
	)
	integrityFailures = promauto.NewCounterVec(
		prometheus.CounterOpts{
			Name: "integrity_failures_total",
			Help: "Data integrity verification failures",
		},
		[]string{"source", "reason"},
	)
)

// SignedEnvelope wraps all external data with integrity verification
type SignedEnvelope struct {
	Version     int    `json:"version"`
	SchemaID    string `json:"schema_id"`
	SourceID    string `json:"source_id"`
	Timestamp   int64  `json:"timestamp"`
	PayloadHash string `json:"payload_hash"`
	Payload     []byte `json:"payload"`
	Signature   string `json:"signature"`
}

// TrustedSource represents a verified data source
type TrustedSource struct {
	ID              string
	PublicKey       ed25519.PublicKey
	AllowedSchemas  []string
	MaxPayloadSize  int
	RateLimitPerMin int
	LastSeen        time.Time
}

// SchemaValidator validates payloads against known schemas
type SchemaValidator interface {
	Validate(schemaID string, data []byte) error
	IsRegistered(schemaID string) bool
}

// SecureDeserializer handles safe deserialization with integrity checks
type SecureDeserializer struct {
	trustedSources  map[string]*TrustedSource
	schemaValidator SchemaValidator
	mu              sync.RWMutex
	logger          *slog.Logger
	maxClockSkew    time.Duration
	replayWindow    map[string]time.Time
	replayMu        sync.Mutex
}

func NewSecureDeserializer(validator SchemaValidator) *SecureDeserializer {
	return &SecureDeserializer{
		trustedSources:  make(map[string]*TrustedSource),
		schemaValidator: validator,
		logger: slog.New(slog.NewJSONHandler(os.Stdout, &slog.HandlerOptions{
			Level: slog.LevelInfo,
		})),
		maxClockSkew: 5 * time.Minute,
		replayWindow: make(map[string]time.Time),
	}
}

// RegisterTrustedSource adds a verified source with its public key
func (sd *SecureDeserializer) RegisterTrustedSource(source *TrustedSource) error {
	if len(source.PublicKey) != ed25519.PublicKeySize {
		return errors.New("invalid public key size")
	}
	if source.MaxPayloadSize <= 0 || source.MaxPayloadSize > 10*1024*1024 {
		source.MaxPayloadSize = 1024 * 1024 // 1MB default
	}

	sd.mu.Lock()
	defer sd.mu.Unlock()
	sd.trustedSources[source.ID] = source

	sd.logger.Info("registered trusted source",
		slog.String("source_id", source.ID),
		slog.Int("allowed_schemas", len(source.AllowedSchemas)),
	)
	return nil
}

// DeserializeSecure performs full integrity verification before deserialization
func (sd *SecureDeserializer) DeserializeSecure(
	ctx context.Context,
	envelopeData []byte,
	target interface{},
) error {
	// Parse envelope structure first
	var envelope SignedEnvelope
	if err := json.Unmarshal(envelopeData, &envelope); err != nil {
		integrityFailures.WithLabelValues("unknown", "invalid_envelope").Inc()
		return fmt.Errorf("invalid envelope format: %w", err)
	}

	// Version check for future compatibility
	if envelope.Version != 1 {
		integrityFailures.WithLabelValues(envelope.SourceID, "unsupported_version").Inc()
		return errors.New("unsupported envelope version")
	}

	// Look up trusted source
	sd.mu.RLock()
	source, exists := sd.trustedSources[envelope.SourceID]
	sd.mu.RUnlock()

	if !exists {
		integrityFailures.WithLabelValues(envelope.SourceID, "unknown_source").Inc()
		sd.logger.Warn("deserialization from unknown source",
			slog.String("source_id", envelope.SourceID),
		)
		return errors.New("unknown source")
	}

	// Verify timestamp freshness (prevent replay attacks)
	if err := sd.verifyTimestamp(envelope); err != nil {
		integrityFailures.WithLabelValues(envelope.SourceID, "timestamp").Inc()
		return err
	}

	// Verify payload size
	if len(envelope.Payload) > source.MaxPayloadSize {
		integrityFailures.WithLabelValues(envelope.SourceID, "payload_too_large").Inc()
		return errors.New("payload exceeds maximum size")
	}

	// Verify schema is allowed for this source
	if !sd.isSchemaAllowed(source, envelope.SchemaID) {
		integrityFailures.WithLabelValues(envelope.SourceID, "unauthorized_schema").Inc()
		sd.logger.Warn("schema not allowed for source",
			slog.String("source_id", envelope.SourceID),
			slog.String("schema_id", envelope.SchemaID),
		)
		return errors.New("schema not authorized for source")
	}

	// Verify payload hash integrity
	computedHash := sha256.Sum256(envelope.Payload)
	expectedHash, err := base64.StdEncoding.DecodeString(envelope.PayloadHash)
	if err != nil || len(expectedHash) != sha256.Size {
		integrityFailures.WithLabelValues(envelope.SourceID, "invalid_hash").Inc()
		return errors.New("invalid payload hash format")
	}

	if !constantTimeCompare(computedHash[:], expectedHash) {
		integrityFailures.WithLabelValues(envelope.SourceID, "hash_mismatch").Inc()
		sd.logger.Error("payload hash mismatch - possible tampering",
			slog.String("source_id", envelope.SourceID),
		)
		return errors.New("payload integrity check failed")
	}

	// Verify cryptographic signature
	signedData := fmt.Sprintf("%d|%s|%s|%d|%s",
		envelope.Version,
		envelope.SchemaID,
		envelope.SourceID,
		envelope.Timestamp,
		envelope.PayloadHash,
	)

	signature, err := base64.StdEncoding.DecodeString(envelope.Signature)
	if err != nil {
		integrityFailures.WithLabelValues(envelope.SourceID, "invalid_signature_format").Inc()
		return errors.New("invalid signature format")
	}

	if !ed25519.Verify(source.PublicKey, []byte(signedData), signature) {
		integrityFailures.WithLabelValues(envelope.SourceID, "signature_invalid").Inc()
		sd.logger.Error("signature verification failed",
			slog.String("source_id", envelope.SourceID),
		)
		return errors.New("signature verification failed")
	}

	// Validate against schema before deserializing
	if err := sd.schemaValidator.Validate(envelope.SchemaID, envelope.Payload); err != nil {
		integrityFailures.WithLabelValues(envelope.SourceID, "schema_validation").Inc()
		return fmt.Errorf("schema validation failed: %w", err)
	}

	// Finally, deserialize the validated payload
	if err := json.Unmarshal(envelope.Payload, target); err != nil {
		deserializationAttempts.WithLabelValues(envelope.SourceID, envelope.SchemaID, "parse_error").Inc()
		return fmt.Errorf("deserialization failed: %w", err)
	}

	deserializationAttempts.WithLabelValues(envelope.SourceID, envelope.SchemaID, "success").Inc()
	sd.logger.Info("successful secure deserialization",
		slog.String("source_id", envelope.SourceID),
		slog.String("schema_id", envelope.SchemaID),
	)

	return nil
}

func (sd *SecureDeserializer) verifyTimestamp(envelope SignedEnvelope) error {
	msgTime := time.Unix(envelope.Timestamp, 0)
	now := time.Now()

	// Check for clock skew
	if msgTime.After(now.Add(sd.maxClockSkew)) {
		return errors.New("timestamp in future")
	}
	if msgTime.Before(now.Add(-sd.maxClockSkew)) {
		return errors.New("timestamp too old")
	}

	// Check for replay
	replayKey := fmt.Sprintf("%s:%d:%s", envelope.SourceID, envelope.Timestamp, envelope.PayloadHash)
	sd.replayMu.Lock()
	defer sd.replayMu.Unlock()

	if _, seen := sd.replayWindow[replayKey]; seen {
		return errors.New("replay detected")
	}
	sd.replayWindow[replayKey] = now

	return nil
}

func (sd *SecureDeserializer) isSchemaAllowed(source *TrustedSource, schemaID string) bool {
	for _, allowed := range source.AllowedSchemas {
		if allowed == schemaID {
			return true
		}
	}
	return false
}

func constantTimeCompare(a, b []byte) bool {
	if len(a) != len(b) {
		return false
	}
	var result byte
	for i := 0; i < len(a); i++ {
		result |= a[i] ^ b[i]
	}
	return result == 0
}
```

**Defense in Depth Layers**:

1. **Source Authentication**:
```go
// Only accept data from pre-registered sources with known public keys
source, exists := sd.trustedSources[envelope.SourceID]
if !exists {
    return errors.New("unknown source")
}
```

2. **Cryptographic Signature Verification**:
```go
// Ed25519 signature ensures data hasn't been tampered
if !ed25519.Verify(source.PublicKey, []byte(signedData), signature) {
    return errors.New("signature verification failed")
}
```

3. **Schema Validation Before Parse**:
```go
// Validate structure before allowing deserialization
if err := sd.schemaValidator.Validate(envelope.SchemaID, envelope.Payload); err != nil {
    return fmt.Errorf("schema validation failed: %w", err)
}
```

4. **Replay Attack Prevention**:
```go
// Timestamp freshness + seen message tracking
if _, seen := sd.replayWindow[replayKey]; seen {
    return errors.New("replay detected")
}
```

**Additional Protections**:
- **Per-source schema allowlists**: Sources can only send data types they're authorized for
- **Payload size limits**: Prevents resource exhaustion from oversized payloads  
- **Constant-time comparison**: Prevents timing attacks on hash/signature verification
- **Comprehensive metrics**: Track all deserialization attempts for anomaly detection
- **Structured logging**: Full audit trail with source, schema, and outcome
- **Version field**: Enables secure protocol upgrades without breaking changes
- **Background replay cache cleanup**: Periodic goroutine removes old entries to prevent memory exhaustion

Deserializing untrusted data in JavaScript is extremely dangerous and has led to numerous remote code execution vulnerabilities. The node-serialize vulnerability (CVE-2017-5941) demonstrated how attackers can achieve full server compromise through unsafe deserialization.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const serialize = require('node-serialize');
const cookieParser = require('cookie-parser');

const app = express();
app.use(cookieParser());
app.use(express.json());

// DANGEROUS: Deserializing untrusted user input
app.get('/profile', (req, res) => {
  const userPrefs = req.cookies.preferences;

  if (userPrefs) {
    // VULNERABLE: Directly deserializing cookie data
    const preferences = serialize.unserialize(userPrefs);
    res.json({ preferences: preferences });
  } else {
    res.json({ preferences: {} });
  }
});

// DANGEROUS: Accepting serialized data from request body
app.post('/update-settings', (req, res) => {
  const { serializedSettings } = req.body;

  // VULNERABLE: Deserializing request body without validation
  const settings = serialize.unserialize(serializedSettings);

  // Store settings...
  res.json({ success: true, settings });
});

app.listen(3000);
```

**Attack Payload**:
```javascript
