  const signature = crypto.createHmac('sha256', SIGNING_KEY)
    .update(json)
    .digest('hex');
  return Buffer.from(`${json}.${signature}`).toString('base64');
}

// SECURE: Verify signature before parsing
function verifyAndParse(signedData) {
  try {
    const decoded = Buffer.from(signedData, 'base64').toString('utf8');
    const lastDotIndex = decoded.lastIndexOf('.');
    if (lastDotIndex === -1) return null;

    const json = decoded.substring(0, lastDotIndex);
    const signature = decoded.substring(lastDotIndex + 1);

    const expectedSignature = crypto.createHmac('sha256', SIGNING_KEY)
      .update(json)
      .digest('hex');

    // Timing-safe comparison
    if (!crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expectedSignature))) {
      return null;
    }

    return JSON.parse(json);
  } catch (e) {
    return null;
  }
}

app.get('/profile', (req, res) => {
