  if (userPrefs) {
    // SECURE: Verify signature and use safe JSON.parse
    const preferences = verifyAndParse(userPrefs);

    if (!preferences || !validatePreferences(preferences)) {
      return res.status(400).json({ error: 'Invalid preferences' });
    }

    res.json({ preferences });
  } else {
    res.json({ preferences: { theme: 'system' } });
  }
