// SECURE: Custom serializer with type preservation
class SafeSerializer {
  static ALLOWED_TYPES = ['string', 'number', 'boolean', 'null', 'date', 'array', 'object'];

  static serialize(obj) {
    const transformed = this.transform(obj);
    return JSON.stringify(transformed);
  }

  static transform(value) {
    if (value === null) return { type: 'null', value: null };
    if (value instanceof Date) {
      return { type: 'date', value: value.toISOString() };
    }
    if (Array.isArray(value)) {
      return { type: 'array', value: value.map(v => this.transform(v)) };
    }
    if (typeof value === 'object') {
      const transformed = Object.create(null);
      for (const [k, v] of Object.entries(value)) {
        transformed[k] = this.transform(v);
      }
      return { type: 'object', value: transformed };
    }
    return { type: typeof value, value: value };
  }

  static deserialize(jsonString) {
    const parsed = safeJSONParse(jsonString);
    if (!parsed) return null;
    return this.restore(parsed);
  }

  static restore(wrapped) {
    if (!wrapped || !this.ALLOWED_TYPES.includes(wrapped.type)) {
      throw new Error('Invalid type in serialized data');
    }

    switch (wrapped.type) {
      case 'null': return null;
      case 'string': return String(wrapped.value);
      case 'number': {
        const num = Number(wrapped.value);
        if (!Number.isFinite(num)) throw new Error('Invalid number');
        return num;
      }
      case 'boolean': return Boolean(wrapped.value);
      case 'date': {
        const date = new Date(wrapped.value);
        if (isNaN(date.getTime())) throw new Error('Invalid date');
        return date;
      }
      case 'array': return wrapped.value.map(v => this.restore(v));
      case 'object': {
        const obj = Object.create(null);
        for (const [k, v] of Object.entries(wrapped.value)) {
          obj[k] = this.restore(v);
        }
        return obj;
      }
      default: throw new Error('Unknown type');
    }
  }
}

// SECURE: Integrity-protected data wrapper
class IntegrityProtectedData {
  constructor(encryptionKey, signingKey) {
    this.encryptionKey = Buffer.from(encryptionKey, 'hex');
    this.signingKey = Buffer.from(signingKey, 'hex');
  }

  wrap(data, expiresInMs = 3600000) {
    const payload = {
      data: SafeSerializer.serialize(data),
      exp: Date.now() + expiresInMs,
      jti: crypto.randomBytes(16).toString('hex')
