    const iv = crypto.randomBytes(12);
    const cipher = crypto.createCipheriv('aes-256-gcm', this.encryptionKey, iv);
    const encrypted = Buffer.concat([cipher.update(payloadJson, 'utf8'), cipher.final()]);
    const authTag = cipher.getAuthTag();

    // Sign
    const toSign = Buffer.concat([iv, authTag, encrypted]);
    const signature = crypto.createHmac('sha256', this.signingKey).update(toSign).digest();

    return Buffer.concat([signature, iv, authTag, encrypted]).toString('base64url');
  }

  unwrap(wrapped) {
    try {
      const buffer = Buffer.from(wrapped, 'base64url');

      const signature = buffer.subarray(0, 32);
      const iv = buffer.subarray(32, 44);
      const authTag = buffer.subarray(44, 60);
      const encrypted = buffer.subarray(60);

      // Verify signature
      const toVerify = Buffer.concat([iv, authTag, encrypted]);
      const expectedSig = crypto.createHmac('sha256', this.signingKey).update(toVerify).digest();

      if (!crypto.timingSafeEqual(signature, expectedSig)) {
        logger.warn('Signature verification failed');
        return null;
      }

