      if (payload.exp < Date.now()) {
        logger.info('Token expired');
        return null;
      }

      return SafeSerializer.deserialize(payload.data);
    } catch (e) {
      logger.error('Unwrap failed', { error: e.message });
      return null;
    }
  }
